// src/pages/Contact.js
import React from 'react';
import contactImage from '../Assets/contactbanner.png';

const ContactForm = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    subject: '',
    message: ''
  });
};
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
    // Here you can add the code to send the form data to your backend or an email service
  };

function Contact() {
  return (
    <div>
      <section
      className="relative h-64 bg-cover bg-center"
      style={{ backgroundImage: `url(${contactImage})`, backgroundPosition: 'center top' }}
    >
      <div className="absolute inset-0 bg-blue-900 bg-opacity-50 flex justify-start items-center p-8">
        <h1 className="text-white text-3xl font-bold">CONTACT US</h1>
      </div>
    </section>
    </div>
  );
}

export default Contact;
